const body = $input.first().json.body || $input.first().json;
return [{
  json: {
    cotizacion_id: (body.cotizacion_id || '').trim(),
    decision:      (body.decision || '').trim().toLowerCase(),
    nombre:        (body.nombre || '').trim(),
    telefono:      (body.telefono || '').trim()
  }
}];

const d = $input.first().json;
if (!d.cotizacion_id)
  return [{ json: { ...d, valido: false, error_code: 400, error_msg: 'cotizacion_id es requerido' } }];
if (!['recoger', 'envio'].includes(d.decision))
  return [{ json: { ...d, valido: false, error_code: 422, error_msg: 'decision debe ser recoger o envio. Recibido: ' + d.decision } }];
return [{ json: { ...d, valido: true } }];

const d = $('Validar Campos').first().json;
const rows = $input.all();
if (!rows || rows.length === 0 || !rows[0].json.cotizacion_id) {
  return [{ json: { ...d, valido_cot: false, error_code: 404, error_msg: 'Cotizacion no encontrada: ' + d.cotizacion_id } }];
}
const cot = rows[0].json;
const estadosValidos = ['elegido_marca', 'elegido_economico', 'pendiente_entrega', 'pendiente_pago'];
if (!estadosValidos.includes(cot.estado)) {
  return [{ json: { ...d, valido_cot: false, error_code: 409, error_msg: 'Estado invalido para entrega: ' + cot.estado, estado_actual: cot.estado } }];
}
return [{ json: {
  cotizacion_id: d.cotizacion_id,
  decision: d.decision,
  nombre: d.nombre || cot.nombre || '',
  telefono: d.telefono || cot.telefono || '',
  colegio: cot.colegio || '',
  grado: cot.grado || '',
  total_marca: cot.total_marca,
  total_economico: cot.total_economico,
  estado_anterior: cot.estado,
  nuevo_estado: d.decision === 'recoger' ? 'pendiente_retiro' : 'pendiente_envio',
  valido_cot: true
} }];

const d = $('Validar Estado Cotizacion').first().json;
const esEnvio = d.decision === 'envio';

// Mensaje para ADMIN (Telegram)
const emoji = esEnvio ? '🚚' : '🏪';
const accion = esEnvio ? 'solicito ENVIO a domicilio' : 'recogeré en TIENDA';
const msg_admin = [
  emoji + ' *Decisión de Entrega*',
  '━━━━━━━━━━━━━━━━━━━',
  '🆔 `' + d.cotizacion_id + '`',
  '📅 ' + new Date().toLocaleString('es-PE', { timeZone: 'America/Lima' }),
  '━━━━━━━━━━━━━━━━━━━',
  '👤 ' + (d.nombre || 'N/A'),
  '📞 ' + (d.telefono || 'N/A'),
  '🏫 ' + (d.colegio || 'N/A') + ' — ' + (d.grado || 'N/A'),
  '━━━━━━━━━━━━━━━━━━━',
  emoji + ' Cliente ' + accion,
  '📊 Estado: *' + d.nuevo_estado.toUpperCase() + '*'
].join('\n');

// Respuesta al cliente
let mensaje_cliente;
if (esEnvio) {
  mensaje_cliente = 'Perfecto. Un asesor se contactará contigo para coordinar el envío a domicilio. ¡Gracias por tu preferencia!';
} else {
  mensaje_cliente = 'Perfecto. Puedes pasar a recoger tus útiles a nuestra tienda. ¡Te esperamos!';
}

const webhook_response = {
  exito: true,
  cotizacion_id: d.cotizacion_id,
  decision: d.decision,
  estado: d.nuevo_estado,
  mensaje: mensaje_cliente
};

return [{ json: { msg_admin, webhook_response } }];

